    titleUrdu: "\u067e\u0627\u0646\u06cc \u06a9\u0627 \u0628\u062d\u0631\u0627\u0646 - 1 \u0645\u06be\u06cc\u0646\u06d2 \u0633\u06d2 \u067e\u0627\u0646\u06cc \u0646\u06be\u06cc\u06ba",
