      "\u0628\u0646\u06cc\u0627\u062f\u06cc: \u0644\u06cc\u0627\u0631\u06cc \u0645\u06cc\u06ba \u0627\u0646\u0641\u0631\u0627\u062f\u06cc \u0633\u0645\u0627\u0631\u0679 \u0645\u06cc\u0679\u0631\u0681 \u0644\u06af\u0627\u0626\u06cc\u06ba \u062a\u0627\u06a9\u06d2 \u062a\u0627\u06a9\u06d2 \u0627\u06cc\u0645\u0627\u0646\u0686\u0627\u0631 \u0635\u0627\u0631\u0641 \u0633\u0632\u0627 \u0646\u06be \u0633\u0632\u0627 \u0633\u0632\u0627 \u0648\u0627\u0644\u06d2.",
      "\u0636\u0631\u0648\u0631\u062a: NEPRA \u06a9\u0648 NA \u06a9\u0645\u06cc\u0679\u06cc \u06a9\u06d2 \u062d\u06a9\u0645 \u0646\u0627\u0641\u0630 \u06a9\u0631\u0646\u0627 \u0686\u0627\u0647\u06cc\u06d2.",
